from __future__ import annotations

import os
import subprocess
import sys
import tempfile
from pathlib import Path

from codex.config import load_config
from scripts.render_workflow_preview import render_preview

CANONICAL_POLICY = {
    "sandbox": "workspace_write",
    "approval_policy": "on_request",
}


def _assert_legacy_config_compatibility() -> None:
    with tempfile.TemporaryDirectory(prefix="compat_fixture_") as tmp:
        compat_fixture = Path(tmp) / "legacy_config.toml"
        compat_fixture.write_text(
            '[policy]\n'
            'sandbox = "workspace-write"\n'
            'approval_policy = "on_request"\n',
            encoding="utf-8",
        )
        loaded = load_config(compat_fixture)
    if loaded != CANONICAL_POLICY:
        raise SystemExit(f"legacy config did not normalize to canonical policy: {loaded!r}")


def _assert_preview_contract() -> None:
    preview = render_preview("codex/config.toml")
    if preview["sandbox"] != CANONICAL_POLICY["sandbox"]:
        raise SystemExit(f"preview sandbox drifted: {preview['sandbox']!r}")
    if preview["approval_policy"] != CANONICAL_POLICY["approval_policy"]:
        raise SystemExit(f"preview approval policy drifted: {preview['approval_policy']!r}")
    job_approvals = {job["approval_policy"] for job in preview["jobs"]}
    if job_approvals != {CANONICAL_POLICY["approval_policy"]}:
        raise SystemExit(f"preview job approval policy drifted: {sorted(job_approvals)!r}")


def _assert_workflow_contract() -> None:
    workflow = Path(".github/workflows/ci.yml").read_text(encoding="utf-8")
    if "workspace-write" in workflow:
        raise SystemExit("workflow still emits deprecated sandbox token 'workspace-write'")
    if "manual-review" in workflow:
        raise SystemExit("workflow still emits deprecated approval token 'manual-review'")
    if workflow.count("SANDBOX_POLICY: workspace_write") != 2:
        raise SystemExit("workflow jobs do not consistently emit canonical sandbox policy")
    if workflow.count("APPROVAL_POLICY: on_request") != 2:
        raise SystemExit("workflow jobs do not consistently emit canonical approval policy")


def main() -> int:
    _assert_legacy_config_compatibility()
    _assert_preview_contract()
    _assert_workflow_contract()
    env = os.environ.copy()
    return subprocess.call([sys.executable, "-m", "pytest", "-q", "tests"], env=env)


if __name__ == "__main__":
    raise SystemExit(main())

